import React, { useState, useEffect } from 'react';
import ListingCard from '../components/ListingCard';
import SearchForm from '../components/SearchForm';
import API from '../services/api';
import './Home.css';

function Home() {
  const [listings, setListings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filters, setFilters] = useState({
    city: '',
    dealType: 'sale',
    minPrice: '',
    maxPrice: '',
    rooms: ''
  });

  // Загрузка при первом открытии и при изменении фильтров
  useEffect(() => {
    loadListings();
  }, [filters]); // ← Срабатывает при любом изменении filters

  const loadListings = async () => {
    setLoading(true);
    setError(null);

    try {
      // Формируем параметры запроса
      const params = new URLSearchParams();

      if (filters.city) params.append('city', filters.city);
      if (filters.dealType) params.append('deal_type', filters.dealType);
      if (filters.minPrice) params.append('min_price', filters.minPrice);
      if (filters.maxPrice) params.append('max_price', filters.maxPrice);
      if (filters.rooms) params.append('rooms', filters.rooms);

      params.append('page_size', '50'); // Показываем до 50 объявлений

      const response = await API.get(`/listings/?${params}`);
      setListings(response.data);
    } catch (err) {
      console.error('Ошибка загрузки:', err);
      setError('Не удалось загрузить объявления');
      setListings([]);
    } finally {
      setLoading(false);
    }
  };

  // Обработчик изменения фильтров (вызывается из SearchForm)
  const handleFilterChange = (newFilters) => {
    setFilters(newFilters); // Это вызовет useEffect и перезагрузку
  };

  return (
    <div className="home-page">
      <h1>Поиск недвижимости</h1>

      {/* Форма поиска (без кнопки) */}
      <SearchForm
        filters={filters}
        onFilterChange={handleFilterChange}
      />

      {error && <div className="error">{error}</div>}

      {loading ? (
        <div className="loader">Загрузка объявлений...</div>
      ) : (
        <>
          <div className="results-info">
            <p>Найдено {listings.length} объявлений</p>
          </div>

          {listings.length === 0 ? (
            <div className="no-results">
              <p>Объявлений не найдено</p>
              <p>Попробуйте изменить параметры поиска</p>
            </div>
          ) : (
            <div className="listings-grid">
              {listings.map(listing => (
                <ListingCard key={listing.listing_id} listing={listing} />
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default Home;
